import React, { useState, useRef, useEffect, useMemo } from 'react';
import { Play, Pause, Download, Wand2, Maximize2, Minimize2, Loader2, Clock, Film, Shuffle, Sparkles, LayoutTemplate, Database, Palette, ImageIcon, Mic, Volume2, Image as ImageDown, Globe, RefreshCw, Type, Bot, Music, FileUp, UploadCloud, Layers, Upload, Eye, EyeOff, Video, CheckSquare, Square, Pin, Edit3, Camera, X, FileAudio } from 'lucide-react';
import { TableData, AnimationConfig, Theme, AnimationStyle, Layout, ImageStyle, BgVisibility } from './types';
import { DEFAULT_TABLE_DATA, DEFAULT_ANIMATION_CONFIG } from './constants';
import { TablePreview } from './components/TablePreview';
import { ImagePreview } from './components/ImagePreview';
import { Editor } from './components/Editor';
import { DataEditorModal } from './components/DataEditorModal';
import { generateTableFromPrompt, fixTableJson, generateBackgroundImage, generateVoiceover, generateSummaryFromData, generateTableFromImage } from './services/geminiService';
import { renderVideo } from './utils/videoRenderer';
import { renderTableImage } from './utils/imageRenderer';
import { createWavBlob } from './utils/audioSynth';
import { clsx } from 'clsx';

const AVAILABLE_VOICES = ['Kore', 'Puck', 'Charon', 'Fenrir', 'Zephyr'];

function App() {
  const [data, setData] = useState<TableData>(DEFAULT_TABLE_DATA);
  const [jsonString, setJsonString] = useState<string>(JSON.stringify(DEFAULT_TABLE_DATA, null, 2));
  const [isValidJson, setIsValidJson] = useState(true);
  const [jsonError, setJsonError] = useState<string | null>(null);

  const [isPlaying, setIsPlaying] = useState(false);
  const [isFullscreen, setIsFullscreen] = useState(false);
  const [isGenerating, setIsGenerating] = useState(false);
  const [isAnalyzingImage, setIsAnalyzingImage] = useState(false);
  const [isDataEditorOpen, setIsDataEditorOpen] = useState(false);

  const [isExporting, setIsExporting] = useState(false); 
  const [exportProgress, setExportProgress] = useState(0);

  const [prompt, setPrompt] = useState("");
  const [showPromptInput, setShowPromptInput] = useState(false);

  const [config, setConfig] = useState<AnimationConfig>(DEFAULT_ANIMATION_CONFIG);

  const [sidebarTab, setSidebarTab] = useState<'data' | 'design'>('data');
  const [viewMode, setViewMode] = useState<'video' | 'image'>('video');

  const [isGenImage, setIsGenImage] = useState(false);
  const [isGenVoice, setIsGenVoice] = useState(false);
  const [voicePcm, setVoicePcm] = useState<string | null>(null);
  const [narrativeLanguage, setNarrativeLanguage] = useState<'auto' | 'en' | 'ne'>('auto');
  const [selectedVoice, setSelectedVoice] = useState('Kore');

  // Camera State
  const [showCamera, setShowCamera] = useState(false);
  const [cameraStream, setCameraStream] = useState<MediaStream | null>(null);
  const videoRef = useRef<HTMLVideoElement>(null);
  const canvasRef = useRef<HTMLCanvasElement>(null);

  const appContainerRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const bgInputRef = useRef<HTMLInputElement>(null);

  // Derive filtered table data based on selected columns for image preview
  const filteredImageData = useMemo(() => {
    if (viewMode !== 'image') return data;
    const indices = config.selectedColumnIndices || [0];
    const finalIndices = config.pinFirstColumn && !indices.includes(0) ? [0, ...indices] : indices;

    const sortedIndices: number[] = Array.from<number>(new Set(finalIndices)).sort((a, b) => a - b);

    return {
      ...data,
      columns: sortedIndices.map((i: number) => data.columns[i] || `Col ${i}`),
      data: data.data.map(row => sortedIndices.map((i: number) => row[i] || ""))
    };
  }, [data, config.selectedColumnIndices, config.pinFirstColumn, viewMode]);

  const handleJsonChange = (newJson: string) => {
    setJsonString(newJson);
    try {
      const parsed = JSON.parse(newJson);
      if (parsed.columns && Array.isArray(parsed.columns) && parsed.data && Array.isArray(parsed.data)) {
        setData(parsed);
        setIsValidJson(true);
        setJsonError(null);
        if (parsed.columns.length !== data.columns.length) {
          setConfig(prev => ({ 
            ...prev, 
            columnWeights: undefined,
            selectedColumnIndices: parsed.columns.map((_: any, i: number) => i)
          }));
        }
      } else {
        throw new Error("Missing 'columns' or 'data' array.");
      }
    } catch (e: any) {
      setIsValidJson(false);
      setJsonError(e.message);
    }
  };

  const handleDataEditorSave = (newData: TableData) => {
    setData(newData);
    setJsonString(JSON.stringify(newData, null, 2));
    setIsValidJson(true);
    setJsonError(null);
    if (newData.columns.length !== data.columns.length) {
       setConfig(prev => ({ 
         ...prev, 
         selectedColumnIndices: newData.columns.map((_: any, i: number) => i),
         columnWeights: undefined 
       }));
    }
  };

  const handleGenerate = async () => {
    if (!prompt.trim()) return;
    setIsGenerating(true);
    try {
      const newData = await generateTableFromPrompt(prompt);
      const formatted = JSON.stringify(newData, null, 2);
      setJsonString(formatted);
      setData(newData);
      setIsValidJson(true);
      setShowPromptInput(false);
      setVoicePcm(null); 
      setConfig(prev => ({ 
        ...prev, 
        backgroundImage: undefined, 
        columnWeights: undefined,
        selectedColumnIndices: newData.columns.map((_: any, i: number) => i)
      }));
    } catch (error) {
      const errMsg = error instanceof Error ? error.message : String(error);
      if (errMsg.includes('429')) {
         alert("API Quota Exceeded. Please wait a moment.");
      } else {
         alert("Failed to generate table.");
      }
    } finally {
      setIsGenerating(false);
    }
  };

  const processImagesForTable = async (base64Images: string[]) => {
    if (base64Images.length === 0) return;
    setIsAnalyzingImage(true);
    try {
      const newData = await generateTableFromImage(base64Images);
      const formatted = JSON.stringify(newData, null, 2);
      setJsonString(formatted);
      setData(newData);
      setIsValidJson(true);
      setShowPromptInput(false);
      setVoicePcm(null);
      setConfig(prev => ({ 
        ...prev, 
        backgroundImage: undefined, 
        columnWeights: undefined,
        selectedColumnIndices: newData.columns.map((_: any, i: number) => i)
      }));
    } catch (error) {
      alert("Could not extract table data from image(s).");
    } finally {
      setIsAnalyzingImage(false);
    }
  };

  const handleImageUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (!files || files.length === 0) return;
    const base64Promises: Promise<string>[] = [];
    for (let i = 0; i < files.length; i++) {
        const file = files[i];
        base64Promises.push(new Promise((resolve) => {
            const reader = new FileReader();
            reader.onload = (event) => resolve(event.target?.result as string);
            reader.readAsDataURL(file);
        }));
    }
    try {
        const base64Images = await Promise.all(base64Promises);
        await processImagesForTable(base64Images);
    } catch (err) {
        console.error("Error processing uploads", err);
    }
    e.target.value = "";
  };

  const handleBgUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (event) => {
        const base64 = event.target?.result as string;
        if (base64) setConfig(prev => ({ ...prev, backgroundImage: base64 }));
    };
    reader.readAsDataURL(file);
    e.target.value = "";
  };

  useEffect(() => {
    const handlePaste = async (e: ClipboardEvent) => {
        const items = e.clipboardData?.items;
        if (!items) return;
        const base64Promises: Promise<string>[] = [];
        for (let i = 0; i < items.length; i++) {
            if (items[i].type.indexOf("image") !== -1) {
                const blob = items[i].getAsFile();
                if (blob) {
                    base64Promises.push(new Promise((resolve) => {
                         const reader = new FileReader();
                         reader.onload = (event) => resolve(event.target?.result as string);
                         reader.readAsDataURL(blob);
                    }));
                }
            }
        }
        if (base64Promises.length > 0) {
            e.preventDefault();
            try {
                const base64Images = await Promise.all(base64Promises);
                await processImagesForTable(base64Images);
            } catch(err) {
                console.error("Error processing pasted images", err);
            }
        }
    };
    window.addEventListener('paste', handlePaste);
    return () => window.removeEventListener('paste', handlePaste);
  }, []);

  const handleFixJson = async () => {
    setIsGenerating(true);
    try {
      const fixedData = await fixTableJson(jsonString);
      setJsonString(JSON.stringify(fixedData, null, 2));
      setData(fixedData);
      setIsValidJson(true);
      setJsonError(null);
      setConfig(prev => ({ 
        ...prev, 
        columnWeights: undefined,
        selectedColumnIndices: fixedData.columns.map((_: any, i: number) => i)
      }));
    } catch (error) {
      alert("Could not fix JSON automatically.");
    } finally {
      setIsGenerating(false);
    }
  };

  const handleGenerateBackground = async () => {
      if (!data.title) return;
      setIsGenImage(true);
      try {
          const base64Img = await generateBackgroundImage(data.title);
          setConfig(prev => ({ ...prev, backgroundImage: base64Img }));
      } catch (e) {
          alert("Failed to generate image.");
      } finally {
          setIsGenImage(false);
      }
  };

  const handleRegenerateSummary = async () => {
      setIsGenVoice(true);
      try {
          const summary = await generateSummaryFromData(data, narrativeLanguage);
          const newData = { ...data, summary };
          setData(newData);
          setJsonString(JSON.stringify(newData, null, 2));
          setVoicePcm(null);
      } catch(e) {
          alert("Failed to regenerate summary.");
      } finally {
          setIsGenVoice(false);
      }
  };

  const handleGenerateVoice = async () => {
      setIsGenVoice(true);
      try {
          let summaryText = data.summary;
          if (!summaryText || summaryText.trim() === '') {
              summaryText = await generateSummaryFromData(data, narrativeLanguage);
              const newData = { ...data, summary: summaryText };
              setData(newData);
              setJsonString(JSON.stringify(newData, null, 2));
          }
          if (summaryText) {
            const pcm = await generateVoiceover(summaryText, selectedVoice);
            setVoicePcm(pcm);
          }
      } catch (e) {
          alert("Failed to generate voiceover.");
      } finally {
          setIsGenVoice(false);
      }
  };

  const handleDownloadVoice = () => {
      if (!voicePcm) return;
      try {
          const blob = createWavBlob(voicePcm, 24000);
          const url = URL.createObjectURL(blob);
          const a = document.createElement('a');
          a.href = url;
          const fileName = data.title ? data.title.toLowerCase().replace(/[^a-z0-9]/g, '_') : 'narration';
          a.download = `${fileName}_audio.wav`;
          document.body.appendChild(a);
          a.click();
          document.body.removeChild(a);
          URL.revokeObjectURL(url);
      } catch (e) {
          alert("Failed to download audio.");
      }
  };

  const handleRandomizeDesign = () => {
    const themes = Object.values(Theme);
    const styles = Object.values(AnimationStyle);
    const layouts = Object.values(Layout);
    setConfig(prev => ({
        ...prev,
        theme: themes[Math.floor(Math.random() * themes.length)],
        style: styles[Math.floor(Math.random() * styles.length)],
        layout: layouts[Math.floor(Math.random() * layouts.length)],
        columnWeights: undefined
    }));
  };

  const toggleFullscreen = () => {
    if (!document.fullscreenElement) {
      appContainerRef.current?.requestFullscreen().then(() => setIsFullscreen(true));
    } else {
      document.exitFullscreen().then(() => setIsFullscreen(false));
    }
  };

  useEffect(() => {
    const handler = () => setIsFullscreen(!!document.fullscreenElement);
    document.addEventListener('fullscreenchange', handler);
    return () => document.removeEventListener('fullscreenchange', handler);
  }, []);

  const handleExportVideo = async () => {
    if (isExporting) return;
    setIsExporting(true);
    setExportProgress(0);
    setIsPlaying(false);
    try {
        const blob = await renderVideo(data, config, voicePcm, (p) => setExportProgress(Math.round(p * 100)));
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = `loksewa-${config.theme}-${Date.now()}.mp4`;
        a.click();
        URL.revokeObjectURL(url);
    } catch (err: any) {
        alert("Export failed: " + err.message);
    } finally {
        setIsExporting(false);
        setExportProgress(0);
    }
  };

  const handleExportImage = async () => {
      if (isExporting) return;
      setIsExporting(true);
      try {
          const indices = config.selectedColumnIndices || [0];
          const pinFirst = config.pinFirstColumn;
          const secondaryIndices = pinFirst ? indices.filter(i => i !== 0) : indices;
          if (config.exportSplitColumns && secondaryIndices.length > 1) {
              const baseTitle = data.title || "Export";
              const primaryIdx = pinFirst ? 0 : -1;
              const primaryCol = primaryIdx !== -1 ? data.columns[primaryIdx] : null;
              for (const secIdx of secondaryIndices) {
                  const finalCols = primaryCol !== null ? [primaryCol, data.columns[secIdx]] : [data.columns[secIdx]];
                  const finalRows = data.data.map(row => primaryIdx !== -1 ? [row[primaryIdx], row[secIdx]] : [row[secIdx]]);
                  const partialData: TableData = { ...data, title: baseTitle, columns: finalCols, data: finalRows };
                  const dataUrls = await renderTableImage(partialData, config);
                  for (let i = 0; i < dataUrls.length; i++) {
                      const a = document.createElement('a');
                      a.href = dataUrls[i];
                      const suffix = dataUrls.length > 1 ? `_part${i+1}` : '';
                      a.download = `post-${data.columns[secIdx].replace(/[^a-z0-9]/gi, '_').toLowerCase()}${suffix}.png`;
                      document.body.appendChild(a);
                      a.click();
                      document.body.removeChild(a);
                      await new Promise(r => setTimeout(r, 600));
                  }
              }
          } else {
              const dataUrls = await renderTableImage(filteredImageData, config);
              for (let i = 0; i < dataUrls.length; i++) {
                  const a = document.createElement('a');
                  a.href = dataUrls[i];
                  const suffix = dataUrls.length > 1 ? `_part${i+1}` : '';
                  a.download = `loksewa-post-${Date.now()}${suffix}.png`;
                  document.body.appendChild(a);
                  a.click();
                  document.body.removeChild(a);
                  await new Promise(r => setTimeout(r, 600));
              }
          }
      } catch (e) {
          alert("Failed to export image(s)");
      } finally {
          setIsExporting(false);
      }
  };

  const toggleColumnSelection = (idx: number) => {
      const current = config.selectedColumnIndices || [];
      let next: number[];
      if (current.includes(idx)) next = current.filter(i => i !== idx);
      else next = [...current, idx];
      setConfig(prev => ({ ...prev, selectedColumnIndices: next, columnWeights: undefined }));
  };

  useEffect(() => {
    if (showCamera) {
      let activeStream: MediaStream | null = null;
      const startStream = async () => {
        try {
          const stream = await navigator.mediaDevices.getUserMedia({ video: { facingMode: 'environment' } });
          activeStream = stream;
          setCameraStream(stream);
          if (videoRef.current) videoRef.current.srcObject = stream;
        } catch (err) {
          alert("Could not access camera. Please check permissions.");
          setShowCamera(false);
        }
      };
      startStream();
      return () => {
        if (activeStream) activeStream.getTracks().forEach(track => track.stop());
        setCameraStream(null);
      };
    }
  }, [showCamera]);

  const handleCapture = () => {
    if (videoRef.current && canvasRef.current) {
      const video = videoRef.current;
      const canvas = canvasRef.current;
      canvas.width = video.videoWidth;
      canvas.height = video.videoHeight;
      const ctx = canvas.getContext('2d');
      if (ctx) {
        ctx.drawImage(video, 0, 0, canvas.width, canvas.height);
        const base64 = canvas.toDataURL('image/jpeg', 0.8);
        setShowCamera(false);
        processImagesForTable([base64]);
      }
    }
  };

  return (
    <div className="min-h-screen bg-slate-950 text-slate-100 flex flex-col font-sans">
      <input type="file" ref={fileInputRef} accept="image/*" multiple className="hidden" onChange={handleImageUpload} />
      <input type="file" ref={bgInputRef} accept="image/*" className="hidden" onChange={handleBgUpload} />

      <DataEditorModal isOpen={isDataEditorOpen} onClose={() => setIsDataEditorOpen(false)} initialData={data} onSave={handleDataEditorSave} />

      {showCamera && (
        <div className="fixed inset-0 z-[100] bg-black flex flex-col">
          <div className="relative flex-1 bg-black overflow-hidden flex items-center justify-center">
             <video ref={videoRef} autoPlay playsInline muted className="absolute inset-0 w-full h-full object-cover" />
             <div className="absolute top-4 right-4 z-10">
               <button onClick={() => setShowCamera(false)} className="p-3 bg-black/50 text-white rounded-full backdrop-blur-md hover:bg-black/70 transition-colors">
                 <X size={24} />
               </button>
             </div>
             <div className="absolute inset-0 border-[40px] border-black/30 pointer-events-none flex items-center justify-center">
                <div className="w-64 h-64 border-2 border-white/50 rounded-lg relative">
                    <div className="absolute top-0 left-0 w-4 h-4 border-t-4 border-l-4 border-white"></div>
                    <div className="absolute top-0 right-0 w-4 h-4 border-t-4 border-r-4 border-white"></div>
                    <div className="absolute bottom-0 left-0 w-4 h-4 border-b-4 border-l-4 border-white"></div>
                    <div className="absolute bottom-0 right-0 w-4 h-4 border-b-4 border-r-4 border-white"></div>
                </div>
             </div>
          </div>
          <div className="h-32 bg-black flex items-center justify-center gap-8 pb-8">
             <button onClick={() => setShowCamera(false)} className="text-white font-medium hover:text-slate-300">Cancel</button>
             <button onClick={handleCapture} className="w-16 h-16 rounded-full bg-white border-4 border-slate-300 flex items-center justify-center shadow-lg active:scale-95 transition-transform">
                <div className="w-14 h-14 rounded-full bg-white border-2 border-black" />
             </button>
             <div className="w-12"></div>
          </div>
          <canvas ref={canvasRef} className="hidden" />
        </div>
      )}

      {!isFullscreen && (
        <header className="px-4 md:px-6 py-3 md:py-4 border-b border-slate-800 bg-slate-900/50 backdrop-blur-md flex items-center justify-between sticky top-0 z-50">
          <div className="flex items-center gap-2 md:gap-3">
            <h1 className="text-lg md:text-xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-blue-400 to-purple-400">Loksewa Automatic</h1>
          </div>
          <div className="flex items-center gap-2 md:gap-3">
             <button onClick={() => setIsDataEditorOpen(true)} className="flex items-center justify-center gap-2 w-10 h-10 md:w-auto md:px-4 md:py-2 bg-slate-800 hover:bg-slate-700 rounded-full text-sm font-medium border border-slate-700 transition-all">
              <Edit3 size={16} className="text-blue-400" /> <span className="hidden md:inline">Edit Data</span>
            </button>
             <button onClick={() => { setShowPromptInput(!showPromptInput); if(!showPromptInput) setSidebarTab('data'); }} className="flex items-center justify-center gap-2 w-10 h-10 md:w-auto md:px-4 md:py-2 bg-slate-800 hover:bg-slate-700 rounded-full text-sm font-medium border border-slate-700 transition-all">
              <Wand2 size={16} className="text-purple-400" /> <span className="hidden md:inline">AI Generate</span>
            </button>
            <button onClick={handleExportImage} className="flex items-center justify-center gap-2 w-10 h-10 md:w-auto md:px-4 md:py-2 bg-purple-600/10 hover:bg-purple-600/20 text-purple-400 rounded-full text-sm font-medium border border-purple-600/20 transition-all">
                <ImageIcon size={16} /> <span className="hidden md:inline">Social Post</span>
            </button>
            <button onClick={handleExportVideo} className="flex items-center justify-center gap-2 w-10 h-10 md:w-auto md:px-4 md:py-2 bg-blue-600/10 hover:bg-blue-600/20 text-blue-400 rounded-full text-sm font-medium border border-blue-600/20 transition-all">
              {isExporting ? <Loader2 size={16} className="animate-spin"/> : <Download size={16} />} <span className="hidden md:inline">{isExporting ? "Exporting..." : "Video"}</span>
            </button>
          </div>
        </header>
      )}

      <main className={clsx("flex-1 flex overflow-hidden flex-col md:flex-row p-4 md:p-6 gap-4 md:gap-6", isFullscreen && "p-0 gap-0")}>
        <div ref={appContainerRef} className={clsx("relative flex flex-col items-center justify-center order-1 md:order-2", isFullscreen ? "h-screen w-screen bg-black" : "w-full md:flex-1 h-[500px] md:h-auto")}>
           {isExporting && (
             <div className="absolute inset-0 z-[60] bg-slate-950/90 backdrop-blur-sm flex flex-col items-center justify-center space-y-6">
                 <div className="relative w-24 h-24 rounded-full border-4 border-slate-800 flex items-center justify-center">
                    <div className="w-full h-full rounded-full border-4 border-t-purple-500 border-r-blue-500 border-b-transparent border-l-transparent animate-spin absolute inset-0"/>
                    <span className="text-2xl font-bold text-white">{exportProgress}%</span>
                 </div>
                 <h2 className="text-xl font-bold text-white">{exportProgress > 0 ? "Composing..." : "Preparing..."}</h2>
             </div>
           )}

           <div className={clsx("absolute top-4 z-50 flex flex-col items-center gap-4 transition-opacity", isExporting && "hidden")}>
                <div className="flex bg-slate-800/80 backdrop-blur p-1 rounded-full border border-white/10 shadow-2xl">
                    <button onClick={() => setViewMode('video')} className={clsx("flex items-center gap-2 px-6 py-2 rounded-full text-xs font-bold transition-all", viewMode === 'video' ? "bg-blue-500 text-white" : "text-slate-400 hover:text-white")}><Video size={14} /> Video</button>
                    <button onClick={() => setViewMode('image')} className={clsx("flex items-center gap-2 px-6 py-2 rounded-full text-xs font-bold transition-all", viewMode === 'image' ? "bg-purple-500 text-white" : "text-slate-400 hover:text-white")}><ImageIcon size={14} /> Image</button>
                </div>
                <div className="flex items-center gap-2 p-2 rounded-full bg-slate-800/80 backdrop-blur border border-white/10 shadow-2xl">
                    {viewMode === 'video' && (
                        <>
                        <button onClick={() => setIsPlaying(!isPlaying)} className="w-10 h-10 rounded-full bg-blue-500 hover:bg-blue-400 text-white flex items-center justify-center">{isPlaying ? <Pause size={20} fill="currentColor" /> : <Play size={20} fill="currentColor" className="ml-1" />}</button>
                        <div className="w-px h-6 bg-white/20 mx-1" />
                        </>
                    )}
                    <button onClick={handleRandomizeDesign} className="p-2 text-slate-300 hover:text-white rounded-full"><Shuffle size={20} /></button>
                    <button onClick={toggleFullscreen} className="p-2 text-slate-300 hover:text-white rounded-full">{isFullscreen ? <Minimize2 size={20} /> : <Maximize2 size={20} />}</button>
                </div>
           </div>

           {viewMode === 'video' ? (
               <TablePreview data={data} config={config} isPlaying={isPlaying} onAnimationComplete={() => setIsPlaying(false)} isFullscreen={isFullscreen} voicePcm={voicePcm} />
           ) : (
               <ImagePreview data={filteredImageData} config={config} onConfigChange={setConfig} />
           )}

           {isAnalyzingImage && (
             <div className="absolute inset-0 z-50 bg-black/60 backdrop-blur-sm flex flex-col items-center justify-center">
                 <Loader2 className="animate-spin text-purple-400 mb-2" size={48} />
                 <p className="text-white font-bold text-lg">Analyzing Images with Gemini AI...</p>
                 <p className="text-slate-300 text-sm mt-1">Merging data from multiple sources</p>
             </div>
           )}
        </div>

        {!isFullscreen && (
          <div className="w-full md:w-1/3 md:min-w-[350px] flex flex-col bg-slate-900 rounded-xl border border-slate-800 shadow-xl overflow-hidden order-2 md:order-1 h-[500px] md:h-auto">
            <div className="flex border-b border-slate-800 shrink-0">
                <button onClick={() => setSidebarTab('data')} className={clsx("flex-1 py-3 text-sm font-medium flex items-center justify-center gap-2 transition-colors relative", sidebarTab === 'data' ? "text-blue-400 bg-slate-800/50" : "text-slate-500")}>
                    <Database size={16} /> Data {sidebarTab === 'data' && <div className="absolute bottom-0 left-0 w-full h-0.5 bg-blue-500" />}
                </button>
                <button onClick={() => setSidebarTab('design')} className={clsx("flex-1 py-3 text-sm font-medium flex items-center justify-center gap-2 transition-colors relative", sidebarTab === 'design' ? "text-purple-400 bg-slate-800/50" : "text-slate-500")}>
                    <Palette size={16} /> {viewMode === 'video' ? 'Video' : 'Image'} Design {sidebarTab === 'design' && <div className="absolute bottom-0 left-0 w-full h-0.5 bg-purple-500" />}
                </button>
            </div>

            <div className="flex-1 overflow-hidden relative flex flex-col">
                {sidebarTab === 'data' && (
                    <div className="flex-1 flex flex-col p-4 gap-4 h-full overflow-hidden">
                        <div className="flex flex-col gap-2">
                          <button onClick={() => setIsDataEditorOpen(true)} className="w-full flex items-center justify-center gap-2 py-3 bg-blue-600/10 hover:bg-blue-600/20 text-blue-400 rounded-xl border border-blue-600/20 transition-all font-bold text-sm"><Edit3 size={18} /> Interactive Data Studio</button>
                          {showPromptInput && (
                          <div className="bg-slate-800 p-4 rounded-xl border border-slate-700 shadow-lg shrink-0">
                              <label className="block text-sm font-medium text-slate-400 mb-2">What data do you need?</label>
                              <div className="flex gap-2">
                                  <input type="text" value={prompt} onChange={(e) => setPrompt(e.target.value)} placeholder="e.g. Nepali Rivers" className="flex-1 bg-slate-900 border border-slate-600 rounded-lg px-3 py-2 text-sm focus:outline-none" onKeyDown={(e) => e.key === 'Enter' && handleGenerate()} />
                                  <button onClick={() => fileInputRef.current?.click()} className="bg-slate-700 hover:bg-slate-600 text-slate-200 rounded-lg px-3 flex items-center justify-center" title="Upload Image(s)"><FileUp size={18} /></button>
                                  <button onClick={() => setShowCamera(true)} className="bg-slate-700 hover:bg-slate-600 text-slate-200 rounded-lg px-3 flex items-center justify-center" title="Take Photo"><Camera size={18} /></button>
                                  <button onClick={handleGenerate} disabled={isGenerating || !prompt} className="bg-purple-600 hover:bg-purple-500 text-white rounded-lg px-3 flex items-center justify-center">{isGenerating ? <Loader2 className="animate-spin" size={18}/> : <Wand2 size={18} />}</button>
                              </div>
                          </div>
                          )}
                        </div>
                        <Editor jsonString={jsonString} setJsonString={handleJsonChange} isValid={isValidJson} errorMessage={jsonError} />
                        {!isValidJson && <button onClick={handleFixJson} className="mt-2 text-xs text-blue-400 flex items-center gap-1 self-end"><Wand2 size={12}/> Auto-fix JSON</button>}
                    </div>
                )}

                {sidebarTab === 'design' && (
                     <div className="flex-1 overflow-y-auto p-4 md:p-6 custom-scrollbar">
                        <div className="space-y-6">
                            {viewMode === 'video' ? (
                                <>
                                    <h3 className="text-sm font-bold text-slate-400 uppercase tracking-wider">Appearance</h3>
                                    <div className="grid grid-cols-2 gap-4">
                                        <div className="space-y-2">
                                            <div className="text-xs text-slate-500 font-semibold uppercase">Theme</div>
                                            <select value={config.theme} onChange={(e) => setConfig({...config, theme: e.target.value as Theme})} className="w-full bg-slate-800 border border-slate-700 text-slate-200 text-sm rounded-lg p-2.5">
                                                {Object.values(Theme).map(t => <option key={t} value={t}>{t}</option>)}
                                            </select>
                                        </div>
                                        <div className="space-y-2">
                                            <div className="text-xs text-slate-500 font-semibold uppercase">Layout</div>
                                            <select value={config.layout} onChange={(e) => setConfig({...config, layout: e.target.value as Layout})} className="w-full bg-slate-800 border border-slate-700 text-slate-200 text-sm rounded-lg p-2.5">
                                                {Object.values(Layout).map(l => <option key={l} value={l}>{l}</option>)}
                                            </select>
                                        </div>
                                    </div>

                                    <div className="space-y-3 pt-4 border-t border-slate-800">
                                        <div className="text-xs text-slate-500 font-semibold uppercase flex items-center gap-2">Voiceover Studio</div>
                                        <div className="bg-slate-900/50 rounded-xl p-4 space-y-4 border border-slate-800 shadow-inner">
                                            <div className="flex gap-2">
                                                 <select value={narrativeLanguage} onChange={(e) => setNarrativeLanguage(e.target.value as any)} className="flex-1 bg-slate-800 border border-slate-700 text-slate-300 text-[10px] rounded-lg px-2 py-1.5 focus:ring-1 focus:ring-blue-500 outline-none">
                                                        <option value="auto">Auto Detect Lang</option><option value="en">English</option><option value="ne">Nepali</option>
                                                 </select>
                                                 <select value={selectedVoice} onChange={(e) => setSelectedVoice(e.target.value)} className="flex-1 bg-slate-800 border border-slate-700 text-slate-300 text-[10px] rounded-lg px-2 py-1.5 focus:ring-1 focus:ring-blue-500 outline-none">
                                                        {AVAILABLE_VOICES.map(v => <option key={v} value={v}>{v}</option>)}
                                                 </select>
                                                 <button onClick={handleRegenerateSummary} disabled={isGenVoice} className="text-blue-400 hover:bg-blue-500/10 p-1.5 rounded-lg border border-blue-500/20" title="Smart AI Refresh"><RefreshCw size={14} className={isGenVoice ? "animate-spin" : ""} /></button>
                                            </div>

                                            <div className="space-y-1.5">
                                                <div className="flex justify-between items-center">
                                                    <span className="text-[10px] text-slate-500 font-bold uppercase">Custom Narration Text</span>
                                                    {voicePcm && <span className="text-[10px] text-green-500 flex items-center gap-1 font-bold animate-pulse"><Volume2 size={10} /> Audio Ready</span>}
                                                </div>
                                                <textarea value={data.summary || ""} onChange={(e) => setData({...data, summary: e.target.value})} className="w-full bg-slate-950 border border-slate-700 rounded-lg p-3 text-xs text-slate-300 min-h-[80px] focus:ring-1 focus:ring-purple-500 outline-none transition-all placeholder:text-slate-700" placeholder="Enter what the AI should say..." />
                                            </div>

                                            <div className="flex gap-2">
                                                <button onClick={handleGenerateVoice} disabled={isGenVoice} className="flex-1 py-2.5 bg-gradient-to-r from-purple-600 to-blue-600 hover:from-purple-500 hover:to-blue-500 text-white rounded-lg text-xs font-bold flex items-center justify-center gap-2 transition-all shadow-lg shadow-purple-900/20 active:scale-[0.98]">
                                                    {isGenVoice ? <Loader2 size={14} className="animate-spin"/> : <Mic size={14}/>} {voicePcm ? "Update Voice" : "Generate Voice"}
                                                </button>
                                                {voicePcm && (
                                                    <button onClick={handleDownloadVoice} className="px-3 py-2.5 bg-slate-800 hover:bg-slate-700 text-blue-400 rounded-lg border border-slate-700 transition-all flex items-center justify-center" title="Download Narration WAV">
                                                        <FileAudio size={18} />
                                                    </button>
                                                )}
                                            </div>
                                        </div>
                                    </div>

                                    <div className="space-y-2 pt-4 border-t border-slate-800">
                                        <div className="flex justify-between items-center">
                                            <div className="text-xs text-slate-500 font-semibold uppercase flex items-center gap-2">Background Image</div>
                                            {config.backgroundImage && <button onClick={() => setConfig({...config, backgroundImage: undefined})} className="text-[10px] text-red-400">Remove</button>}
                                        </div>
                                        {config.backgroundImage ? (
                                            <div className="relative w-full h-24 rounded-lg overflow-hidden border border-slate-700 group">
                                                <img src={config.backgroundImage} className="w-full h-full object-cover" alt="Background"/>
                                                <div className="absolute inset-0 bg-black/40 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity">
                                                    <button onClick={() => bgInputRef.current?.click()} className="bg-white/20 p-2 rounded-full"><Upload size={16} /></button>
                                                </div>
                                            </div>
                                        ) : (
                                            <div className="flex gap-2">
                                                <button onClick={handleGenerateBackground} disabled={isGenImage || !data.title} className="flex-1 py-3 border border-dashed border-slate-700 rounded-lg text-slate-500 hover:text-blue-400 flex flex-col items-center justify-center gap-1">
                                                    {isGenImage ? <Loader2 size={16} className="animate-spin"/> : <Wand2 size={16}/>}
                                                    <span className="text-[10px]">AI Generated</span>
                                                </button>
                                                <button onClick={() => bgInputRef.current?.click()} className="flex-1 py-3 border border-dashed border-slate-700 rounded-lg text-slate-500 hover:text-purple-400 flex flex-col items-center justify-center gap-1">
                                                    <Upload size={16}/>
                                                    <span className="text-[10px]">Upload Image</span>
                                                </button>
                                            </div>
                                        )}
                                    </div>

                                    <div className="pt-4 border-t border-slate-800 space-y-4">
                                        <h3 className="text-sm font-bold text-slate-400 uppercase tracking-wider">Timing</h3>
                                        <div className="space-y-2">
                                            <label className="text-sm text-slate-300 flex justify-between">
                                                <span>Time per Item</span>
                                                <span className="text-blue-400 font-mono text-xs font-bold">{config.durationPerItem}s</span>
                                            </label>
                                            <input type="range" min="1.0" max="5.0" step="0.5" value={config.durationPerItem} onChange={(e) => setConfig({...config, durationPerItem: parseFloat(e.target.value)})} className="w-full h-2 bg-slate-800 rounded-lg appearance-none cursor-pointer accent-blue-500" />
                                        </div>
                                    </div>
                                </>
                            ) : (
                                <>
                                    <h3 className="text-sm font-bold text-slate-400 uppercase tracking-wider">Image Layout</h3>
                                    <div className="space-y-4">
                                        <div className="space-y-2">
                                            <div className="text-xs text-slate-500 font-semibold uppercase">Global Theme</div>
                                            <select value={config.theme} onChange={(e) => setConfig({...config, theme: e.target.value as Theme})} className="w-full bg-slate-800 border border-slate-700 text-slate-200 text-sm rounded-lg p-2.5">
                                                {Object.values(Theme).map(t => <option key={t} value={t}>{t}</option>)}
                                            </select>
                                        </div>
                                        <div className="space-y-2">
                                            <div className="text-xs text-slate-500 font-semibold uppercase">Social Style</div>
                                            <select value={config.imageStyle} onChange={(e) => setConfig({...config, imageStyle: e.target.value as ImageStyle, columnWeights: undefined})} className="w-full bg-slate-800 border border-slate-700 text-slate-200 text-sm rounded-lg p-2.5">
                                                {Object.values(ImageStyle).map(s => <option key={s} value={s}>{s.replace('_', ' ')}</option>)}
                                            </select>
                                        </div>
                                    </div>

                                    <div className="pt-4 border-t border-slate-800 space-y-3">
                                        <h3 className="text-sm font-bold text-slate-400 uppercase tracking-wider">Column Selection</h3>
                                        <div className="space-y-2 max-h-[200px] overflow-y-auto pr-2 custom-scrollbar">
                                            <div className="flex items-center justify-between p-2 bg-slate-800/40 rounded border border-slate-700/50">
                                                <div className="flex items-center gap-2">
                                                    <Pin size={12} className="text-blue-400" />
                                                    <span className="text-xs font-medium text-slate-300">Pin First Column</span>
                                                </div>
                                                <button onClick={() => setConfig({...config, pinFirstColumn: !config.pinFirstColumn, columnWeights: undefined})} className={clsx("p-1 rounded", config.pinFirstColumn ? "text-blue-400" : "text-slate-600")}>
                                                    {config.pinFirstColumn ? <CheckSquare size={18}/> : <Square size={18}/>}
                                                </button>
                                            </div>
                                            {data.columns.map((col, idx) => (
                                                <button key={idx} disabled={config.pinFirstColumn && idx === 0} onClick={() => toggleColumnSelection(idx)} className={clsx("w-full flex items-center justify-between p-2 rounded border transition-all text-left", config.selectedColumnIndices?.includes(idx) ? "bg-purple-600/10 border-purple-600/30 text-white" : "bg-slate-800/40 border-slate-700/50 text-slate-500", config.pinFirstColumn && idx === 0 ? "opacity-50 cursor-not-allowed" : "hover:bg-slate-700/50")}>
                                                    <span className="text-xs font-medium truncate max-w-[180px]">{col}</span>
                                                    {config.selectedColumnIndices?.includes(idx) ? <CheckSquare size={16}/> : <Square size={16}/>}
                                                </button>
                                            ))}
                                        </div>
                                        <div className="flex items-center justify-between p-3 bg-slate-800 rounded-lg border border-slate-700">
                                            <div className="flex flex-col">
                                                <label className="text-xs font-bold text-slate-300">Export Multiple Posts</label>
                                                <span className="text-[10px] text-slate-500">One image per selected col.</span>
                                            </div>
                                            <input type="checkbox" checked={config.exportSplitColumns} onChange={(e) => setConfig({...config, exportSplitColumns: e.target.checked})} className="w-5 h-5 rounded cursor-pointer" />
                                        </div>
                                    </div>

                                    <div className="pt-4 border-t border-slate-800 space-y-5">
                                        <h3 className="text-sm font-bold text-slate-400 uppercase tracking-wider">Typography</h3>
                                        <div className="space-y-2"><label className="text-[11px] font-bold text-slate-400 flex justify-between uppercase"><span>Title Size</span><span className="text-purple-400 font-mono text-xs">{config.imageTitleFontSize}px</span></label><input type="range" min="60" max="220" step="5" value={config.imageTitleFontSize} onChange={(e) => setConfig({...config, imageTitleFontSize: parseInt(e.target.value)})} className="w-full h-2 bg-slate-800 rounded-lg appearance-none cursor-pointer accent-purple-500" /></div>
                                        <div className="space-y-2"><label className="text-[11px] font-bold text-slate-400 flex justify-between uppercase"><span>Header Size</span><span className="text-purple-400 font-mono text-xs">{config.imageHeaderFontSize}px</span></label><input type="range" min="40" max="180" step="2" value={config.imageHeaderFontSize} onChange={(e) => setConfig({...config, imageHeaderFontSize: parseInt(e.target.value)})} className="w-full h-2 bg-slate-800 rounded-lg appearance-none cursor-pointer accent-purple-500" /></div>
                                        <div className="space-y-2"><label className="text-[11px] font-bold text-slate-400 flex justify-between uppercase"><span>Body Text Size</span><span className="text-purple-400 font-mono text-xs">{config.imageBodyFontSize}px</span></label><input type="range" min="30" max="160" step="2" value={config.imageBodyFontSize} onChange={(e) => setConfig({...config, imageBodyFontSize: parseInt(e.target.value)})} className="w-full h-2 bg-slate-800 rounded-lg appearance-none cursor-pointer accent-purple-500" /></div>
                                    </div>

                                    <div className="pt-4 border-t border-slate-800 space-y-5">
                                        <h3 className="text-sm font-bold text-slate-400 uppercase tracking-wider">Spacing & Borders</h3>
                                        <div className="space-y-2"><label className="text-[11px] font-bold text-slate-400 flex justify-between uppercase"><span>Row Padding</span><span className="text-purple-400 font-mono text-xs">{config.imageRowPadding}px</span></label><input type="range" min="10" max="150" step="5" value={config.imageRowPadding} onChange={(e) => setConfig({...config, imageRowPadding: parseInt(e.target.value)})} className="w-full h-2 bg-slate-800 rounded-lg appearance-none cursor-pointer accent-purple-500" /></div>
                                        <div className="space-y-2"><label className="text-[11px] font-bold text-slate-400 flex justify-between uppercase"><span>Column Spacing</span><span className="text-purple-400 font-mono text-xs">{config.imageColumnSpacing}px</span></label><input type="range" min="5" max="250" step="5" value={config.imageColumnSpacing} onChange={(e) => setConfig({...config, imageColumnSpacing: parseInt(e.target.value)})} className="w-full h-2 bg-slate-800 rounded-lg appearance-none cursor-pointer accent-purple-500" /></div>
                                        <div className="space-y-2"><label className="text-[11px] font-bold text-slate-400 flex justify-between uppercase"><span>Border Width</span><span className="text-purple-400 font-mono text-xs">{config.imageBorderWidth}px</span></label><input type="range" min="0" max="20" step="1" value={config.imageBorderWidth} onChange={(e) => setConfig({...config, imageBorderWidth: parseInt(e.target.value)})} className="w-full h-2 bg-slate-800 rounded-lg appearance-none cursor-pointer accent-purple-500" /></div>
                                    </div>
                                </>
                            )}
                        </div>
                     </div>
                )}
            </div>
          </div>
        )}
      </main>
    </div>
  );
}

export default App;
